t = int(input())
for _ in range(t):
    n = int(input())
    a = list(map(int, input().split()))
    best = float('inf')
    for c1 in range(3):
        for c2 in range(3):
            c3_needed = 0
            ok = True
            for x in a:
                found = False
                for x1 in range(min(c1,x)+1):
                    for x2 in range(min(c2,(x-x1)//2)+1):
                        rem = x - x1 - 2*x2
                        if rem >= 0 and rem % 3 == 0:
                            c3_needed = max(c3_needed, rem//3)
                            found = True
                            break
                    if found: break
                if not found:
                    ok = False
                    break
            if ok:
                best = min(best, c1+c2+c3_needed)
    print(best)

